// Basic Function Template - Swap
template<typename T>
void swap(T& a, T& b) {
 T temp = a;
 a = b;
 b = temp;
}

int main() {
 int x = 5, y = 10;
 swap(x, y); // T deduced as int

 double p = 3.14, q = 2.71;
 swap(p, q); // T deduced as double

 return 0;
}

// Multiple Type Parameters
template<typename T1, typename T2>
std::pair<T1, T2> makePair(T1 a, T2 b) {
 return std::pair<T1, T2>(a, b);
}

int main() {
 auto p1 = makePair(10, 3.14); // T1=int, T2=double
 auto p2 = makePair("hello", 42); // T1=const char*, T2=int

 return 0;
}

// Function Template Specialization
template<typename T>
T max(T a, T b) {
 return (a > b) ? a : b;
}

// Full specialization for const char*
template<>
const char* max<const char*>(const char* a, const char* b) {
 return (strcmp(a, b) > 0) ? a : b;
}

int main() {
 int x = max(5, 10); // Uses generic template
 const char* s = max("apple", "banana"); // Uses specialization

 return 0;
}

// Default Template Arguments
template<typename T = int, typename U = double>
void display(T a, U b) {
 std::cout << a << " " << b << std::endl;
}

int main() {
 display(10, 20.5); // T=int, U=double
 display<double>(10, 20); // T=double, U=int (U deduced)
 display<char, std::string>('A', "Hello"); // Both explicit

 return 0;
}

// Non-Type Template Parameters
template<int N>
int multiplyBy() {
 return N * 10;
}

template<std::size_t N>
double getArraySize() {
 return static_cast<double>(N);
}

int main() {
 int result = multiplyBy<5>(); // Returns 50
 double size = getArraySize<100>(); // Returns 100.0

 return 0;
}

// Explicit Template Arguments
template<typename T>
T power(T base, int exp) {
 T result = 1;
 for (int i = 0; i < exp; i++)
 result *= base;
 return result;
}

int main() {
 // Type deduction works
 int x = power(2, 3); // T=int, returns 8

 // Explicit specification overrides deduction
 double y = power<double>(2, 3); // T=double, returns 8.0

 return 0;
}

// SFINAE with enable_if
#include <type_traits>

// Only enabled for integral types
template<typename T>
typename std::enable_if<std::is_integral<T>::value, T>::type
square(T x) {
 return x * x;
}

// Only enabled for floating-point types 
template<typename T>
typename std::enable_if<std::is_floating_point<T>::value, T>::type
square(T x) {
 return x * x;
}

int main() {
 int i = square(5); // Calls integral version, returns 25
 double d = square(3.14); // Calls floating version, returns 9.8596
 // square("test"); // Would cause compile error

 return 0;
}
